// ============================================================================
// Root Store
// ============================================================================

export class RootStore {
  user: UserStore
  game: GameStore
  gamePurchase: GamePurchaseStore
  commissionLedger: CommissionLedgerStore

  constructor() {
    this.user = new UserStore()
    this.game = new GameStore()
    this.gamePurchase = new GamePurchaseStore()
    this.commissionLedger = new CommissionLedgerStore()
    makeAutoObservable(this)
  }

  /** Clear all stores */
  clearAll() {
    this.user.clear()
    this.game.clear()
    this.gamePurchase.clear()
    this.commissionLedger.clear()
  }
}

// ============================================================================
// Factory & Singleton
// ============================================================================

let rootStore: RootStore | null = null

/**
 * Get or create the root store singleton
 */
export function getStore(): RootStore {
  if (!rootStore) {
    rootStore = new RootStore()
  }
  return rootStore
}

/**
 * Create a new root store (for testing or SSR)
 */
export function createStore(): RootStore {
  return new RootStore()
}

/**
 * Reset the singleton store
 */
export function resetStore(): void {
  rootStore = null
}
